// ===== FILTER STATE =====
// ===== MEMBER PASSPORT DATA =====
// In production, this object will be populated from the member's profile in the database
// When a member signs up, their profile data flows into this object and the card auto-updates
const memberPassport = {
  surname: '',
  givenNames: '',
  initials: '',
  nationality: '',
  countryCode: '',
  gender: '',
  genderCode: '',
  dob: '',
  dobMRZ: '',  // YYMMDD
  issueDate: '',
  expiryDate: '',
  expiryMRZ: '',  // YYMMDD
  passportNumber: ''
};

// Function to apply passport data to the card (called on profile update)
function applyPassportData() {
  document.querySelectorAll('[data-field]').forEach(el => {
    const field = el.getAttribute('data-field');
    if (memberPassport[field] !== undefined && field !== 'photo' && field !== 'mrz' && field !== 'mrzLine1' && field !== 'mrzLine2') {
      el.textContent = memberPassport[field];
    }
  });
  
  // Build custom MRZ-style lines
  // Format: >>>>>>NZL>Given>Surname<<<<<<<<<<
  //         >>>>>>PASSPORT_NO>>PNO.>>UAE<<<<<
  const cc = memberPassport.countryCode;
  const givenNames = memberPassport.givenNames;  // mixed case
  const surnameParts = memberPassport.surname.split(' ');  // 'HERMANUS GOES' -> ['HERMANUS', 'GOES']
  
  // Properly case the surname: HERMANUS GOES -> Hermanus<Goes
  const surnameFormatted = surnameParts.map(s => s.charAt(0) + s.slice(1).toLowerCase()).join('<');
  const givenNameFormatted = givenNames.charAt(0) + givenNames.slice(1).toLowerCase();
  
  // Line 1 target: <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<
  const line1Content = cc + '>' + givenNameFormatted + '>' + surnameFormatted;
  const line1LeftFill = '>'.repeat(13);
  const line1RightTotal = 53;  // approximate total chars
  const line1RightFill = '<'.repeat(Math.max(0, line1RightTotal - line1LeftFill.length - line1Content.length));
  const line1 = line1LeftFill + line1Content + line1RightFill;
  
  // Line 2 target: >>>>>>>>>>>>>F1206250001>>PNO.>>UAE<<<<<<<<<<<<<<<<<<
  const line2Content = memberPassport.passportNumber + '>>PNO.>>UAE';
  const line2LeftFill = '>'.repeat(13);
  const line2RightFill = '<'.repeat(Math.max(0, line1.length - line2LeftFill.length - line2Content.length));
  const line2 = line2LeftFill + line2Content + line2RightFill;
  
  const line1El = document.querySelector('[data-field="mrzLine1"]');
  const line2El = document.querySelector('[data-field="mrzLine2"]');
  if (line1El) line1El.textContent = line1;
  if (line2El) line2El.textContent = line2;
}

const state = {
  timeRange: 'all',
  selectedCity: null,
  cityFilter: 'all',
  expandedActivities: false,
  expandedVenues: false,
  expandedRecent: false,
  expandedCities: false,
  mapZoom: 1.5
};

// ===== HELPERS =====
function getFilteredLogs() {
  let logs = LOGS;
  if (state.timeRange === '7d') logs = logs.filter(l => l.daysAgo <= 7);
  else if (state.timeRange === '30d') logs = logs.filter(l => l.daysAgo <= 30);
  else if (state.timeRange === '90d') logs = logs.filter(l => l.daysAgo <= 90);
  else if (state.timeRange === 'year') {
    const days = Math.floor((new Date() - new Date(new Date().getFullYear(), 0, 1)) / 86400000);
    logs = logs.filter(l => l.daysAgo <= days);
  }
  if (state.selectedCity) logs = logs.filter(l => l.city === state.selectedCity);
  return logs;
}

function timeAgo(days) {
  if (days === 0) return 'today';
  if (days === 1) return '1 day ago';
  if (days < 7) return days + ' days ago';
  if (days < 14) return '1 week ago';
  if (days < 30) return Math.floor(days/7) + ' weeks ago';
  return Math.floor(days/30) + ' months ago';
}

// ===== RENDER =====
function renderAll() {
  const logs = getFilteredLogs();
  renderStats(logs);
  renderActivities(logs);
  renderVenues(logs);
  renderRecent(logs);
  renderCities();
  renderMapPins();
}

function renderStats(logs) {
  const venues = new Set(), cities = new Set(), countries = new Set();
  let partner = 0;
  logs.forEach(l => { venues.add(l.venue); cities.add(l.city); countries.add(l.country); if (l.partner) partner++; });
  document.getElementById('stat-activities').textContent = logs.length;
  document.getElementById('stat-venues').textContent = venues.size;
  document.getElementById('stat-cities').textContent = cities.size;
  document.getElementById('stat-countries').textContent = countries.size;
  document.getElementById('stat-partner').textContent = partner;
}

function renderActivities(logs) {
  const map = {};
  logs.forEach(l => {
    if (!map[l.activity]) map[l.activity] = { count: 0, icon: l.icon, cities: new Set() };
    map[l.activity].count++;
    map[l.activity].cities.add(l.city);
  });
  const arr = Object.entries(map).map(([n, d]) => ({ name: n, count: d.count, icon: d.icon, cities: [...d.cities].join(' · ') })).sort((a,b)=>b.count-a.count);
  
  const list = document.getElementById('activities-list');
  const btn = document.getElementById('activities-view-all');
  document.getElementById('activities-count').textContent = arr.length + ' activities';
  
  if (arr.length === 0) {
    list.innerHTML = '<div class="empty-state">No activities in this period</div>';
    btn.style.display = 'none';
    return;
  }
  
  const items = state.expandedActivities ? arr : arr.slice(0, 3);
  const max = arr[0].count;
  list.innerHTML = items.map(a => `
    <div class="ba-row">
      <div class="ba-icon"><span class="material-icons" style="font-size:20px;color:var(--blue);">${a.icon}</span></div>
      <div>
        <div class="ba-name-line"><span class="ba-name">${a.name}</span><span class="ba-cities">${a.cities}</span></div>
        <div class="ba-bar-track"><div class="ba-bar-fill" style="width:${Math.round((a.count/max)*100)}%"></div></div>
      </div>
      <span class="ba-count">${a.count}x</span>
    </div>
  `).join('');
  
  if (arr.length > 3) {
    btn.style.display = '';
    btn.querySelector('.vm-label').textContent = state.expandedActivities ? 'Show fewer' : `View all ${arr.length} activities`;
  } else {
    btn.style.display = 'none';
  }
}

function renderVenues(logs) {
  const map = {};
  logs.forEach(l => {
    if (!map[l.venue]) map[l.venue] = { count: 0, city: l.city + ', ' + l.country };
    map[l.venue].count++;
  });
  const arr = Object.entries(map).map(([n,d])=>({name:n,count:d.count,city:d.city})).sort((a,b)=>b.count-a.count);
  
  const list = document.getElementById('venues-list');
  const btn = document.getElementById('venues-view-all');
  document.getElementById('venues-count').textContent = arr.length + ' venues';
  
  if (arr.length === 0) {
    list.innerHTML = '<div class="empty-state">No venues in this period</div>';
    btn.style.display = 'none';
    return;
  }
  
  const items = state.expandedVenues ? arr : arr.slice(0, 3);
  list.innerHTML = items.map((v,i) => `
    <div class="tv-row">
      <span class="tv-rank">${String(i+1).padStart(2,'0')}</span>
      <div><div class="tv-name">${v.name}</div><div class="tv-sub">${v.city}</div></div>
      <span class="tv-count">×${v.count}</span>
    </div>
  `).join('');
  
  if (arr.length > 3) {
    btn.style.display = '';
    btn.querySelector('.vm-label').textContent = state.expandedVenues ? 'Show fewer' : `View all ${arr.length} venues`;
  } else {
    btn.style.display = 'none';
  }
}

function renderRecent(logs) {
  const arr = [...logs].sort((a,b)=>a.daysAgo-b.daysAgo);
  const list = document.getElementById('recent-list');
  const btn = document.getElementById('recent-view-all');
  
  if (arr.length === 0) {
    list.innerHTML = '<div class="empty-state">No recent activity in this period</div>';
    btn.style.display = 'none';
    return;
  }
  
  const items = state.expandedRecent ? arr : arr.slice(0, 3);
  list.innerHTML = items.map(r => `
    <div class="ra-row">
      <div class="ra-icon"><span class="material-icons" style="font-size:20px;color:var(--blue);">${r.icon}</span></div>
      <div>
        <div class="ra-name"><span>${r.activity}</span>${r.partner ? '<span class="partner-badge"><span class="material-icons" style="font-size:11px;">verified</span>Partner</span>' : ''}</div>
        <div class="ra-meta">${r.venue} · ${r.city} · ${timeAgo(r.daysAgo)}</div>
      </div>
      <div class="ra-chevron"><span class="material-icons" style="font-size:18px;">chevron_right</span></div>
    </div>
  `).join('');
  
  if (arr.length > 3) {
    btn.style.display = '';
    btn.querySelector('.vm-label').textContent = state.expandedRecent ? 'Show fewer' : 'View full history';
  } else {
    btn.style.display = 'none';
  }
}

function renderCities() {
  // Cities live on the map now - this just updates the count
  const visitedMap = {};
  LOGS.forEach(l => {
    if (!visitedMap[l.city]) visitedMap[l.city] = { name: l.city, country: l.country, count: 0, status: 'active', favorite: FAVORITES.includes(l.city) };
    visitedMap[l.city].count++;
  });
  WISHLIST.forEach(w => {
    if (!visitedMap[w.name]) visitedMap[w.name] = { name: w.name, country: w.country, count: 0, status: 'wishlist', favorite: w.favorite };
  });
  
  let cities = Object.values(visitedMap);
  if (state.cityFilter === 'visited') cities = cities.filter(c => c.status === 'active');
  else if (state.cityFilter === 'favorites') cities = cities.filter(c => c.favorite);
  else if (state.cityFilter === 'wishlist') cities = cities.filter(c => c.status === 'wishlist');
  
  const countEl = document.getElementById('cities-count');
  if (countEl) countEl.textContent = cities.length + ' cities';
}

// D3 projection - Natural Earth (more accurate than equirectangular)
let mapProjection = null;
let mapPath = null;

function setupMapProjection() {
  // Natural Earth projection - same one used by professional cartographic dashboards
  mapProjection = d3.geoNaturalEarth1()
    .scale(135)
    .translate([400, 200]);
  mapPath = d3.geoPath().projection(mapProjection);
}

function loadWorldMap() {
  // Fetch Natural Earth world map data (public domain, ~30kb)
  fetch('https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json')
    .then(r => r.json())
    .then(world => {
      const countries = topojson.feature(world, world.objects.countries);
      const countriesWithActivity = new Set();
      LOGS.forEach(l => {
        const map = { 'UAE': 'United Arab Emirates', 'UK': 'United Kingdom' };
        countriesWithActivity.add(map[l.country] || l.country);
      });
      
      const g = document.getElementById('world-countries');
      g.innerHTML = countries.features.map(f => {
        const name = f.properties.name;
        const hasActivity = countriesWithActivity.has(name);
        return `<path class="country-path ${hasActivity ? 'has-activity' : ''}" d="${mapPath(f)}" data-country="${name}"/>`;
      }).join('');
      
      // Add tooltips to countries
      g.querySelectorAll('.country-path').forEach(p => {
        const name = p.getAttribute('data-country');
        p.addEventListener('mouseenter', () => showMapTooltip(name));
        p.addEventListener('mouseleave', hideMapTooltip);
      });
      
      renderMapPins();
    })
    .catch(err => {
      console.error('Map load error:', err);
      // Fallback - simple continents
      document.getElementById('world-countries').innerHTML = '<text x="400" y="200" text-anchor="middle" fill="#8a99a8" font-size="14">Map loading...</text>';
    });
}

function showMapTooltip(text, x, y) {
  const tip = document.getElementById('map-tooltip');
  if (!tip) return;
  tip.textContent = text;
  tip.style.display = 'block';
  if (x !== undefined && y !== undefined) {
    tip.style.left = x + 'px';
    tip.style.top = (y - 30) + 'px';
  }
}

function hideMapTooltip() {
  const tip = document.getElementById('map-tooltip');
  if (tip) tip.style.display = 'none';
}

function renderMapPins() {
  if (!mapProjection) return;
  
  const pins = document.getElementById('map-pins');
  
  // Build all cities from LOGS + WISHLIST
  const allCities = {};
  LOGS.forEach(l => {
    if (!allCities[l.city]) allCities[l.city] = { name: l.city, country: l.country, status: 'visited', favorite: FAVORITES.includes(l.city) };
  });
  WISHLIST.forEach(w => {
    if (!allCities[w.name]) allCities[w.name] = { name: w.name, country: w.country, status: 'wishlist', favorite: w.favorite };
  });
  
  // Apply city filter
  let cities = Object.values(allCities);
  if (state.cityFilter === 'visited') cities = cities.filter(c => c.status === 'visited');
  else if (state.cityFilter === 'favorites') cities = cities.filter(c => c.favorite);
  else if (state.cityFilter === 'wishlist') cities = cities.filter(c => c.status === 'wishlist');
  
  let html = '';
  
  // Helper: build a pin SVG based on city status
  // Favorite (any status) = RED ball
  // Visited (non-favorite) = YELLOW ball
  // Wishlist (non-favorite) = SILVER ball
  function pinSvg(city, isSelected) {
    // Pin color matches the current filter context, with priority for 'all'
    let ballColor;
    if (state.cityFilter === 'wishlist') {
      ballColor = 'silver';  // All wishlist shown as silver regardless of favorite
    } else if (state.cityFilter === 'visited') {
      ballColor = city.favorite ? 'red' : 'yellow';  // visited can show favorite
    } else if (state.cityFilter === 'favorites') {
      ballColor = 'red';  // All favorites shown as red
    } else {
      // 'all' filter: priority order
      ballColor = city.favorite ? 'red' : (city.status === 'visited' ? 'yellow' : 'silver');
    }
    const ballGradId = 'ball-' + ballColor;
    
    let stops;
    if (ballColor === 'red') {
      stops = '<stop offset="0%" stop-color="#FF8080"/><stop offset="40%" stop-color="#E63946"/><stop offset="100%" stop-color="#8B0000"/>';
    } else if (ballColor === 'yellow') {
      stops = '<stop offset="0%" stop-color="#FFF099"/><stop offset="40%" stop-color="#FFCC00"/><stop offset="100%" stop-color="#B8860B"/>';
    } else {
      stops = '<stop offset="0%" stop-color="#F0F4F8"/><stop offset="40%" stop-color="#B8C2CC"/><stop offset="100%" stop-color="#5A6470"/>';
    }
    
    const r = isSelected ? 5 : 3.8;
    const ringStroke = ballColor === 'red' ? '#E63946' : (ballColor === 'yellow' ? '#FFCC00' : '#B8C2CC');
    
    return `
      <ellipse cx="0" cy="1" rx="3" ry="1" fill="rgba(0,0,0,0.5)"/>
      ${isSelected ? `<circle cx="0" cy="0" r="6" fill="none" stroke="${ringStroke}" stroke-width="1" opacity="0.5">
        <animate attributeName="r" from="4" to="14" dur="1.8s" repeatCount="indefinite"/>
        <animate attributeName="opacity" from="0.7" to="0" dur="1.8s" repeatCount="indefinite"/>
      </circle>` : ''}
      <defs>
        <linearGradient id="needle-${city.name.replace(/\s/g,'')}" x1="0%" y1="0%" x2="100%" y2="0%">
          <stop offset="0%" stop-color="#6a7580"/>
          <stop offset="40%" stop-color="#d0d8e0"/>
          <stop offset="60%" stop-color="#e8eef4"/>
          <stop offset="100%" stop-color="#5a6470"/>
        </linearGradient>
        <radialGradient id="${ballGradId}-${city.name.replace(/\s/g,'')}" cx="35%" cy="30%" r="65%">
          ${stops}
        </radialGradient>
      </defs>
      <rect x="-0.7" y="-13" width="1.4" height="13" fill="url(#needle-${city.name.replace(/\s/g,'')})"/>
      <path d="M -0.7,-1 L 0.7,-1 L 0,1 Z" fill="#3a4450"/>
      <circle cx="0" cy="-16" r="${r}" fill="url(#${ballGradId}-${city.name.replace(/\s/g,'')})"/>
      <ellipse cx="-1" cy="-17.2" rx="1" ry="0.7" fill="#fff" opacity="0.85"/>
      <ellipse cx="0" cy="-13.5" rx="3" ry="0.6" fill="rgba(0,0,0,0.4)"/>
      ${isSelected ? `<text y="-23" text-anchor="middle" fill="#fff" font-size="11" font-weight="800" font-family="Montserrat" style="paint-order: stroke; stroke: #0a1828; stroke-width: 3px; pointer-events: none;">${city.name}</text>` : ''}
    `;
  }
  
  // Render pins for all filtered cities
  cities.forEach(city => {
    const c = CITY_COORDS[city.name];
    if (!c) return;
    const [x, y] = mapProjection([c.lng, c.lat]);
    const isSelected = state.selectedCity === city.name;
    html += `<g class="city-pin" data-city="${city.name}" transform="translate(${x},${y})" style="cursor:pointer;">${pinSvg(city, isSelected)}</g>`;
  });
  
  pins.innerHTML = html;
  
  // Show empty state on map if no cities match the filter
  const emptyState = document.getElementById('map-empty-state');
  if (cities.length === 0) {
    if (!emptyState) {
      const mapWrap = document.querySelector('.map-wrap');
      const empty = document.createElement('div');
      empty.id = 'map-empty-state';
      empty.style.cssText = 'position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);background:rgba(8,20,32,0.92);border:1px solid var(--border-mid);border-radius:10px;padding:18px 22px;color:#fff;text-align:center;font-size:13px;font-weight:600;z-index:5;pointer-events:none;max-width:280px;';
      mapWrap.appendChild(empty);
    }
    const empty = document.getElementById('map-empty-state');
    const msg = state.cityFilter === 'wishlist' 
      ? 'No cities in your wish list yet. Click "Add city" to add one.'
      : state.cityFilter === 'favorites'
      ? 'No favorite cities yet. Tap a pin to mark as favorite.'
      : state.cityFilter === 'visited'
      ? 'No visited cities yet. Log an activity to add one.'
      : 'No cities yet.';
    empty.textContent = msg;
    empty.style.display = '';
  } else if (emptyState) {
    emptyState.style.display = 'none';
  }
  
  // Update map subtitle to show selected city
  const sub = document.getElementById('map-sub');
  if (sub) {
    if (state.selectedCity) {
      sub.innerHTML = `<strong style="color:var(--blue);">${state.selectedCity}</strong> — showing stats below`;
    } else {
      const counts = `${cities.length} pin${cities.length !== 1 ? 's' : ''} shown`;
      sub.textContent = `${counts} — tap any pin to see stats`;
    }
  }
  
  console.log('[FFP] Map pins rendered:', cities.length, 'cities | filter:', state.cityFilter);
  
  // Wire up click handlers for the pins
  pins.querySelectorAll('[data-city]').forEach(el => {
    el.addEventListener('click', e => {
      e.stopPropagation();
      e.preventDefault();
      const city = el.getAttribute('data-city');
      if (state.selectedCity === city) {
        // Deselect
        state.selectedCity = null;
        state.mapZoom = 1.5;
        state.mapPanX = 0;
        state.mapPanY = 0;
      } else {
        state.selectedCity = city;
        const c = CITY_COORDS[city];
        if (c) {
          const [px, py] = mapProjection([c.lng, c.lat]);
          state.mapZoom = 3;
          state.mapPanX = (px - 400);
          state.mapPanY = (py - 200);
        }
      }
      renderAll();
      const svg = document.getElementById('world-svg');
      const w = 800 / state.mapZoom, h = 400 / state.mapZoom;
      const baseX = (800 - w) / 2, baseY = (400 - h) / 2;
      svg.setAttribute('viewBox', `${baseX + state.mapPanX} ${baseY + state.mapPanY} ${w} ${h}`);
    });
  });
}

// ===== QR CODE =====
function renderQR() {
  const N = 21;
  let h = 0; const seed = '';
  for (let i = 0; i < seed.length; i++) h = (h * 31 + seed.charCodeAt(i)) >>> 0;
  const cells = [];
  for (let y = 0; y < N; y++) { cells[y] = []; for (let x = 0; x < N; x++) cells[y][x] = 0; }
  // Finder patterns
  function drawFinder(x0, y0) {
    for (let y = 0; y < 7; y++) for (let x = 0; x < 7; x++) {
      if (y === 0 || y === 6 || x === 0 || x === 6 || (y >= 2 && y <= 4 && x >= 2 && x <= 4)) cells[y0+y][x0+x] = 1;
    }
  }
  drawFinder(0, 0); drawFinder(N-7, 0); drawFinder(0, N-7);
  for (let y = 0; y < N; y++) for (let x = 0; x < N; x++) {
    if ((y < 8 && x < 8) || (y < 8 && x > N-9) || (y > N-9 && x < 8)) continue;
    if (y === 6 || x === 6) continue;
    h = (h * 1664525 + 1013904223) >>> 0;
    if ((h % 100) < 48) cells[y][x] = 1;
  }
  const cell = 100 / N;
  let svg = `<svg viewBox="0 0 100 100" xmlns="http://www.w3.org/2000/svg"><rect width="100" height="100" fill="#fff"/>`;
  for (let y = 0; y < N; y++) for (let x = 0; x < N; x++) {
    if (cells[y][x]) svg += `<rect x="${(x*cell).toFixed(2)}" y="${(y*cell).toFixed(2)}" width="${cell.toFixed(2)}" height="${cell.toFixed(2)}" fill="#1a2937"/>`;
  }
  svg += `</svg>`;
  document.getElementById('pass-qr').innerHTML = svg;
}

// ===== TOPBAR =====
function setupTopbar() {
  const notifBtn = document.getElementById('notif-btn');
  const notifMenu = document.getElementById('notif-menu');
  const userBtn = document.getElementById('user-btn');
  const userMenu = document.getElementById('user-menu');
  
  notifBtn.addEventListener('click', e => { e.stopPropagation(); notifMenu.classList.toggle('show'); userMenu.classList.remove('show'); });
  userBtn.addEventListener('click', e => { e.stopPropagation(); userMenu.classList.toggle('show'); notifMenu.classList.remove('show'); });
  document.addEventListener('click', e => {
    if (!e.target.closest('.menu-wrap')) { notifMenu.classList.remove('show'); userMenu.classList.remove('show'); }
  });
  
  // Logout button in user menu
  const logoutBtn = document.getElementById('user-menu-logout');
  if (logoutBtn) {
    logoutBtn.addEventListener('click', () => {
      userMenu.classList.remove('show');
      if (!confirm('Are you sure you want to logout?')) return;
      // v99: wired to ffp-api-integration.js global ffpLogout() — clears
      // localStorage.ffp_token + ffp_member and redirects to login.html.
      if (typeof window.ffpLogout === 'function') {
        window.ffpLogout();
      } else {
        try { localStorage.removeItem('ffp_token'); localStorage.removeItem('ffp_member'); } catch(e) {}
        window.location.href = 'login.html';
      }
    });
  }
}

function clearNotifs() {
  document.getElementById('notif-list').innerHTML = '<div class="empty-state">No notifications</div>';
  document.getElementById('notif-badge').textContent = '0';
}

// ===== PANEL NAVIGATION =====
// Bottom nav AND user menu both switch which .panel-view is active.
// Bottom-nav panels keep an active tab highlight.
// User-menu panels (Profile, Workout Timer, etc.) clear the bottom nav highlight
// because they live outside the bottom nav.
// Hash sync keeps the selected panel after refresh.
function setupPanelNav() {
  const navItems = document.querySelectorAll('.nav-item');
  const userMenuItems = document.querySelectorAll('#user-menu .menu-item[data-panel]');
  
  // Bottom-nav panels — these keep an active tab highlight when shown
  const bottomNavPanels = new Set(
    Array.from(navItems).map(n => n.getAttribute('data-panel')).filter(Boolean)
  );
  
  function showPanel(panelId) {
    // Validate panel exists
    const target = document.getElementById(panelId);
    if (!target) return;
    
    // Swap panel visibility
    document.querySelectorAll('.panel-view').forEach(p => p.classList.remove('active'));
    target.classList.add('active');
    
    // Update bottom nav active state
    navItems.forEach(n => n.classList.remove('active'));
    if (bottomNavPanels.has(panelId)) {
      const navBtn = document.querySelector(`.nav-item[data-panel="${panelId}"]`);
      if (navBtn) navBtn.classList.add('active');
    }
    // If panelId is a user-menu panel, bottom nav stays cleared (no item highlighted)
    
    // Update URL hash (so refresh keeps panel)
    if (window.location.hash !== '#' + panelId) {
      history.replaceState(null, '', '#' + panelId);
    }
    
    // Scroll to top of content area
    window.scrollTo(0, 0);
    
    // If switching back to passport, re-scale the card (in case viewport changed)
    if (panelId === 'panel-passport') {
      setTimeout(scalePassportCard, 50);
    }
  }
  
  // Bottom nav clicks
  navItems.forEach(btn => {
    btn.addEventListener('click', () => {
      const panelId = btn.getAttribute('data-panel');
      if (panelId) showPanel(panelId);
    });
  });
  
  // User menu clicks (also close the menu after click)
  userMenuItems.forEach(btn => {
    btn.addEventListener('click', () => {
      const panelId = btn.getAttribute('data-panel');
      if (panelId) {
        showPanel(panelId);
        document.getElementById('user-menu').classList.remove('show');
      }
    });
  });
  
  // Open panel from URL hash on load (e.g. #panel-deals, #panel-workout-timer)
  const initialHash = window.location.hash.replace('#', '');
  if (initialHash && document.getElementById(initialHash)) {
    showPanel(initialHash);
  }
}

// ===== PROFILE PANEL =====
// MemberProfile.data is now the SINGLE SOURCE OF TRUTH for member identity.
// The passport card (memberPassport object) is a derived view — every profile
// change calls syncToPassport() which mirrors fields into memberPassport and
// calls applyPassportData() + renderQR() so the card updates instantly.
//
// Layout:
//   PERSONAL INFORMATION
//     Given Names | Surname            (2-col)
//     Email                            (full row)
//     Phone (CC + number in card)      (full row)
//     Date of Birth | Gender           (2-col)
//
//   LOCATION
//     Country                          (listed FIRST; full row)
//     City                             (filtered by current country)
//     Nationality                      (full row)
//
//   SECURITY  (6-digit PIN only)
//   SPORTS & SKILL LEVELS  (× to remove each)
//   PREFERENCES

const NATIONALITIES = [
  'Argentinian','Australian','Austrian','Belgian','Brazilian','British','Bulgarian',
  'Canadian','Chilean','Chinese','Colombian','Croatian','Czech','Danish','Dutch',
  'Egyptian','Emirati','Filipino','Finnish','French','German','Greek','Hungarian',
  'Indian','Indonesian','Irish','Israeli','Italian','Japanese','Jordanian','Kenyan',
  'Kuwaiti','Lebanese','Malaysian','Mexican','Moroccan','New Zealander','Nigerian',
  'Norwegian','Omani','Pakistani','Peruvian','Polish','Portuguese','Qatari','Romanian',
  'Russian','Saudi Arabian','Singaporean','South African','South Korean','Spanish',
  'Sri Lankan','Swedish','Swiss','Thai','Turkish','Ukrainian','American','Vietnamese'
];

// Map nationality -> 3-letter ISO code (used on the passport card MRZ line)
