// =====================================================================
// UNIVERSAL PICKER
// =====================================================================
const Picker = {
  current: null,
  open(config) {
    this.current = config;
    document.getElementById('picker-modal-title').textContent = config.title || 'Select';
    document.getElementById('picker-modal-subtitle').textContent = config.subtitle || '';
    const search = document.getElementById('picker-modal-search');
    search.value = '';
    search.placeholder = config.searchPlaceholder || 'Search...';
    this.renderOptions('');
    document.getElementById('picker-modal-overlay').classList.add('show');
    setTimeout(() => search.focus(), 50);
  },
  close() {
    document.getElementById('picker-modal-overlay').classList.remove('show');
    this.current = null;
  },
  normalize(opt) {
    if (typeof opt === 'string') return { value: opt, label: opt, sub: '' };
    return { value: opt.value, label: opt.label || opt.value, sub: opt.sub || '' };
  },
  renderOptions(filterText) {
    const cfg = this.current;
    if (!cfg) return;
    const f = (filterText || '').toLowerCase().trim();
    const container = document.getElementById('picker-modal-options');
    const matches = (opt) => !f ||
      (opt.label || '').toLowerCase().includes(f) ||
      (opt.sub || '').toLowerCase().includes(f) ||
      (opt.value || '').toLowerCase().includes(f);
    const row = (o) => {
      const sel = String(o.value) === String(cfg.current);
      const sub = o.sub ? `<span class="po-sub">${this.escape(o.sub)}</span>` : '';
      const chk = sel ? '<span class="material-icons" style="color:var(--blue);">check</span>' : '<span class="material-icons"></span>';
      return `<div class="picker-option ${sel ? 'selected' : ''}" data-value="${this.escape(String(o.value))}">
        <span>${this.escape(o.label)} ${sub}</span>${chk}</div>`;
    };
    let html = '', count = 0;
    if (cfg.grouped) {
      Object.keys(cfg.options).forEach(g => {
        const items = cfg.options[g].map(o => this.normalize(o)).filter(matches);
        if (!items.length) return;
        html += `<div class="picker-option-group-label">${this.escape(g)}</div>`;
        items.forEach(o => { html += row(o); count++; });
      });
    } else {
      cfg.options.map(o => this.normalize(o)).filter(matches).forEach(o => { html += row(o); count++; });
    }
    if (!count) html = '<div class="picker-empty">No matches.</div>';
    container.innerHTML = html;
    container.querySelectorAll('.picker-option[data-value]').forEach(el => {
      el.addEventListener('click', () => {
        const v = el.getAttribute('data-value');
        const onPick = cfg.onPick;
        this.close();
        if (onPick) onPick(v);
      });
    });
  },
  escape(str) {
    if (str == null) return '';
    return String(str).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  }
};
function openPicker(config) { Picker.open(config); }
function closePicker()      { Picker.close(); }
(function wirePicker() {
  const overlay = document.getElementById('picker-modal-overlay');
  if (!overlay || overlay._wired) return;
  overlay.addEventListener('click', e => { if (e.target.id === 'picker-modal-overlay') closePicker(); });
  document.getElementById('picker-modal-search').addEventListener('input', e => Picker.renderOptions(e.target.value));
  overlay._wired = true;
})();

// =====================================================================
// MEMBER PROFILE — single source of truth for member identity
// =====================================================================
const MemberProfile = {
  data: {
    // Identity (shared with passport card)
    givenNames: '',
    surname: '',
    
    // Contact
    email: '',
    phoneCountryCode: '',
    phoneNumber: '',
    
    // DOB
    dobDay: '',
    dobMonth: '',
    dobYear: '',
    
    gender: '',
    
    // Location
    country: '',  // where you LIVE
    city: '',
    nationality: '',     // passport country (demonym)
    
    // Account meta
    tier: '',
    memberSince: '',
    passportNumber: '',
    issueDate: '',
    expiryDate: '',
    hasPin: false,
    
    // VERIFICATION (admin-set in production — read-only on this profile)
    //   verified            : true once admin confirms this is a real person
    //   professional.roles  : array of { role, verified }
    //                         Each role independently verified by admin.
    //                         null/empty → not a professional profile
    verified: false,
    professional: {
      roles: []
    },
    
    sports: [],
    
    preferences: {
      notifications: false,
      newsletter: false,
      publicProfile: false
    }
  },
  
  // ===== HELPERS =====
  escape(str) {
    if (str == null) return '';
    return String(str).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  },
  
  getInitials() {
    const g = (this.data.givenNames || '').trim().charAt(0).toUpperCase();
    const s = (this.data.surname || '').trim().charAt(0).toUpperCase();
    return (g + s) || 'M';
  },
  
  getFullName() {
    return `${this.data.givenNames} ${this.data.surname}`.trim();
  },
  
  formatDOB() {
    const m = MONTHS.find(x => x.num === this.data.dobMonth);
    return `${this.data.dobDay || ''} ${m ? m.short : ''} ${this.data.dobYear || ''}`.trim();
  },
  
  dobAsISO() {
    if (!this.data.dobYear || !this.data.dobMonth || !this.data.dobDay) return '';
    return `${this.data.dobYear}-${this.data.dobMonth}-${this.data.dobDay.padStart(2,'0')}`;
  },
  
  dobMaxDate() {
    const t = new Date(); t.setFullYear(t.getFullYear() - 13);
    return `${t.getFullYear()}-${String(t.getMonth() + 1).padStart(2,'0')}-${String(t.getDate()).padStart(2,'0')}`;
  },
  
  // Render the Verified badge in the profile header — ONLY if the member is
  // actually admin-verified. No professional role badges here (those live in the
  // Professional Profile section). No fallback "Member" badge.
  renderBadges() {
    if (!this.data.verified) return '';
    return `<span class="ph-badge ph-badge-verified">
      <span class="material-icons">verified</span>Verified
    </span>`;
  },
  
  // Render the Professional Profile section.
  // - If no roles: prompt to add one
  // - If 1+ roles: list each as its own card with a remove X
  //   Each role has its own verified status (admin-set per role).
  //   "Add role" button to declare another. To clear all roles, pick
  //   "Non-professional" from the picker — no separate clear link.
  renderProfessionalCard() {
    const roles = (this.data.professional && this.data.professional.roles) || [];
    
    if (roles.length === 0) {
      return `
        <div class="security-card field-card-picker" onclick="MemberProfile.openRolePicker()">
          <div class="security-card-info">
            <div class="security-card-label">Non-professional member</div>
            <div class="security-card-status">Tap to add a professional role (Powerlifting Coach, Nutritionist, etc.)</div>
          </div>
          <span class="material-icons pt-chevron">arrow_drop_down</span>
        </div>
      `;
    }
    
    const roleCards = roles.map((r, i) => {
      const statusText = r.verified ? 'Verified by FFP admin' : 'Pending verification';
      const statusCls  = r.verified ? 'set' : '';
      return `
        <div class="security-card" style="position:relative;">
          <div class="security-card-info" style="padding-right:24px;">
            <div class="security-card-label">${this.escape(r.role)}</div>
            <div class="security-card-status ${statusCls}">${statusText}</div>
          </div>
          <button class="role-remove" data-role-index="${i}" aria-label="Remove ${this.escape(r.role)}" title="Remove">
            <span class="material-icons">close</span>
          </button>
        </div>
      `;
    }).join('');
    
    return `
      <div class="role-list">${roleCards}</div>
      <button class="role-add-btn" onclick="MemberProfile.openRolePicker()">
        <span class="material-icons">add_circle</span>
        Add another role
      </button>
    `;
  },
  
  // =====================================================================
  // SYNC TO PASSPORT CARD
  // Profile data → memberPassport object → applyPassportData() + renderQR()
  // Called after every profile data change so the passport card reflects edits.
  // =====================================================================
  syncToPassport() {
    if (typeof memberPassport === 'undefined') return;
    memberPassport.surname        = this.data.surname.toUpperCase();
    memberPassport.givenNames     = this.data.givenNames.toUpperCase();
    memberPassport.initials       = this.getInitials();
    memberPassport.nationality    = this.data.nationality.toUpperCase();
    memberPassport.countryCode    = NATIONALITY_ISO[this.data.nationality] || 'XXX';
    memberPassport.gender         = this.data.gender.toUpperCase();
    memberPassport.genderCode     = (this.data.gender.charAt(0) || 'X').toUpperCase();
    memberPassport.dob            = this.formatDOB();
    memberPassport.dobMRZ         = (this.data.dobYear || '').slice(2) + (this.data.dobMonth || '') + (this.data.dobDay || '').padStart(2,'0');
    memberPassport.issueDate      = this.data.issueDate;
    memberPassport.expiryDate     = this.data.expiryDate;
    memberPassport.passportNumber = this.data.passportNumber;
    
    if (typeof applyPassportData === 'function') applyPassportData();
    if (typeof renderQR === 'function')          renderQR();
  },
  
  // ===== RENDER =====
  render() {
    const body = document.getElementById('profile-body');
    if (!body) return;
    const d = this.data;
    
    body.innerHTML = `
      <div class="profile-menu">
        <!-- HEADER -->
        <div class="profile-header">
          <div class="ph-avatar">
            ${this.getInitials()}
            <button class="ph-avatar-edit" onclick="MemberProfile.changeAvatar()" title="Change photo">
              <span class="material-icons">photo_camera</span>
            </button>
          </div>
          <div class="ph-info">
            <div class="ph-name">${this.escape(this.getFullName())}</div>
            ${this.renderBadges() ? `<div class="ph-badges">${this.renderBadges()}</div>` : ''}
            <div class="ph-meta">Member since ${this.escape(d.memberSince)} &middot; ${this.escape(d.passportNumber)}</div>
          </div>
        </div>

        <!-- PERSONAL INFORMATION
             Order: Name (2-col) | Email (full) | Phone (full) | DOB+Gender (2-col)
             Names sync into the passport card surname / given names. -->
        <div class="profile-section-title">Personal Information</div>
        <div class="fields-grid">
          ${this.renderTextCard('givenNames', 'Given Names', d.givenNames)}
          ${this.renderTextCard('surname',    'Surname',     d.surname)}
        </div>
        <div class="fields-grid" style="margin-top:10px;">
          ${this.renderEmailCard()}
          ${this.renderPhoneCard()}
        </div>
        <div class="fields-grid" style="margin-top:10px;">
          ${this.renderDOBCard()}
          ${this.renderPickerCard('gender', 'Gender', d.gender)}
        </div>

        <!-- LOCATION — Country + City on one row (2-col), Nationality on its own row -->
        <div class="profile-section-title">Location</div>
        <div class="fields-grid">
          ${this.renderPickerCard('country', 'Country', d.country)}
          ${this.renderPickerCard('city',    'City',    d.city)}
        </div>
        <div class="fields-grid" style="margin-top:10px;">
          ${this.renderPickerCard('nationality', 'Nationality', d.nationality, true)}
        </div>

        <!-- SECURITY (PIN only) -->
        <div class="profile-section-title">Security</div>
        <div class="security-card">
          <div class="security-card-info">
            <div class="security-card-label">6-digit Sign-in PIN</div>
            <div class="security-card-status ${d.hasPin ? 'set' : ''}">
              ${d.hasPin
                ? '<span class="pin-display">' + Array(6).fill('<span class="pin-dot"></span>').join('') + '</span> &middot; Active'
                : 'Not yet set'}
            </div>
          </div>
          <button class="security-btn" onclick="MemberProfile.openPinModal()">${d.hasPin ? 'Change PIN' : 'Set PIN'}</button>
        </div>

        <!-- PROFESSIONAL PROFILE — member self-declares role; admin verifies separately -->
        <div class="profile-section-title">Professional Profile</div>
        ${this.renderProfessionalCard()}

        <!-- SKILLS & LEVELS — used by Meet & Move for matching -->
        <div class="profile-section-title">
          Skills &amp; Levels
          <button class="section-action" onclick="MemberProfile.addSportFlow()">
            <span class="material-icons">add_circle</span>
            Add skill
          </button>
        </div>
        <div class="sports-grid">
          ${d.sports.length === 0
            ? '<div style="color:var(--muted); font-size:12px; padding:12px;">No skills added yet. Tap &quot;Add skill&quot; to start.</div>'
            : d.sports.map((s, i) => `
              <div class="sport-card">
                <button class="sport-card-remove"
                        data-skill-index="${i}"
                        aria-label="Remove ${this.escape(s.name)}"
                        title="Remove ${this.escape(s.name)}">
                  <span class="material-icons">close</span>
                </button>
                <div class="sport-card-name">${this.escape(s.name)}</div>
                <div class="sport-card-level">${this.escape(s.level)}</div>
              </div>
            `).join('')}
        </div>

        <!-- PREFERENCES -->
        <div class="profile-section-title">Preferences</div>
        <div class="profile-preferences">
          <label class="pref-toggle">
            <span>Notifications</span>
            <input type="checkbox" ${d.preferences.notifications ? 'checked' : ''} onchange="MemberProfile.setPref('notifications', this.checked)">
          </label>
          <label class="pref-toggle">
            <span>Weekly Newsletter</span>
            <input type="checkbox" ${d.preferences.newsletter ? 'checked' : ''} onchange="MemberProfile.setPref('newsletter', this.checked)">
          </label>
          <label class="pref-toggle">
            <span>Public Profile (Meet &amp; Move)</span>
            <input type="checkbox" ${d.preferences.publicProfile ? 'checked' : ''} onchange="MemberProfile.setPref('publicProfile', this.checked)">
          </label>
        </div>
      </div>
    `;
    
    // Keep passport card in sync after every render
    this.syncToPassport();
    
    // Wire role-remove buttons (event delegation, since they appear/disappear)
    document.querySelectorAll('.role-remove[data-role-index]').forEach(btn => {
      btn.addEventListener('click', (e) => {
        e.stopPropagation();
        const i = parseInt(btn.getAttribute('data-role-index'), 10);
        if (!isNaN(i)) MemberProfile.removeRole(i);
      });
    });
    
    // Wire skill-remove buttons (no confirm — just removes, easy to re-add from picker)
    document.querySelectorAll('.sport-card-remove[data-skill-index]').forEach(btn => {
      btn.addEventListener('click', (e) => {
        e.stopPropagation();
        const i = parseInt(btn.getAttribute('data-skill-index'), 10);
        if (!isNaN(i)) MemberProfile.removeSport(i);
      });
    });
  },
  
  // ===== CARD RENDERERS =====
  
  // Generic text field — flat input that looks like display text, edits on focus
  renderTextCard(field, label, value, autocomplete) {
    return `
      <div class="field-card">
        <div class="field-card-label-top">${label}</div>
        <input type="text"
               class="field-card-input-flat"
               value="${this.escape(value)}"
               autocomplete="${autocomplete || 'off'}"
               oninput="MemberProfile.data['${field}'] = this.value"
               onblur="MemberProfile.commit('${field}', this.value)"
               onkeydown="if(event.key==='Enter'){event.preventDefault(); this.blur();}">
      </div>
    `;
  },
  
  renderEmailCard() {
    return `
      <div class="field-card full-width">
        <div class="field-card-label-top">Email</div>
        <input type="email"
               class="field-card-input-flat"
               value="${this.escape(this.data.email)}"
               autocomplete="email"
               inputmode="email"
               placeholder="your@email.com"
               oninput="MemberProfile.data.email = this.value"
               onblur="MemberProfile.commit('email', this.value)"
               onkeydown="if(event.key==='Enter'){event.preventDefault(); this.blur();}">
      </div>
    `;
  },
  
  renderPhoneCard() {
    return `
      <div class="field-card full-width field-card-phone">
        <div class="field-card-label-top">Phone</div>
        <div class="field-card-row">
          <button class="phone-cc" onclick="MemberProfile.pickPhoneCC()">
            <span>${this.escape(this.data.phoneCountryCode)}</span>
            <span class="material-icons">arrow_drop_down</span>
          </button>
          <input type="tel"
                 class="field-card-input-flat phone-num"
                 value="${this.escape(this.data.phoneNumber)}"
                 autocomplete="tel-national"
                 inputmode="tel"
                 placeholder="56 261 7359"
                 oninput="MemberProfile.data.phoneNumber = this.value"
                 onblur="MemberProfile.commit('phoneNumber', this.value)"
                 onkeydown="if(event.key==='Enter'){event.preventDefault(); this.blur();}">
        </div>
      </div>
    `;
  },
  
  renderDOBCard() {
    const iso = this.dobAsISO();
    return `
      <div class="field-card field-card-dob">
        <div class="field-card-label-top">Date of Birth</div>
        <div class="field-card-row">
          <span class="dob-display">${this.escape(this.formatDOB() || 'Tap to set')}</span>
          <span class="material-icons dob-icon">calendar_today</span>
        </div>
        <input type="date"
               class="dob-native"
               value="${iso}"
               min="1900-01-01"
               max="${this.dobMaxDate()}"
               onchange="MemberProfile.setDOBFromNative(this.value)">
      </div>
    `;
  },
  
  renderPickerCard(field, label, value, fullWidth) {
    const isEmpty = !value;
    return `
      <div class="field-card field-card-picker${fullWidth ? ' full-width' : ''}" onclick="MemberProfile.openFieldPicker('${field}')">
        <div class="field-card-label-top">${label}</div>
        <div class="field-card-row">
          <span class="field-card-display ${isEmpty ? 'muted' : ''}">${this.escape(value || 'Tap to choose')}</span>
          <span class="material-icons pt-chevron">arrow_drop_down</span>
        </div>
      </div>
    `;
  },
  
  // ===== COMMITS (flat inputs save on blur/Enter) =====
  commit(field, value) {
    const trimmed = (value || '').trim();
    if (!trimmed) { this.render(); return; }    // revert empty
    if (this.data[field] === trimmed) return;   // no change
    this.data[field] = trimmed;
    // PRODUCTION: PATCH /api/members/me { [field]: trimmed }
    this.render();
  },
  
  // ===== PHONE COUNTRY CODE =====
  pickPhoneCC() {
    openPicker({
      title: 'Country Code',
      searchPlaceholder: 'Search countries or codes...',
      options: COUNTRY_CODES.map(c => ({ value: c.code, label: c.code, sub: c.country })),
      current: this.data.phoneCountryCode,
      onPick: (val) => { this.data.phoneCountryCode = val; this.render(); }
    });
  },
  
  // ===== PROFESSIONAL ROLES =====
  // Multiple roles supported. Each has its own admin-set verified flag.
  // Picker always has "Non-professional" as the first option — picking it clears ALL roles.
  // Picking any specific role ADDS it to the array (no duplicates).
  openRolePicker() {
    // Build options: special "Non-professional" entry first, then full taxonomy grouped
    const currentRoles = (this.data.professional && this.data.professional.roles) || [];
    const currentRoleNames = currentRoles.map(r => r.role);
    
    // Wrap the grouped taxonomy with a synthetic "Status" group at the top
    const groupedOptions = { 'Status': ['Non-professional'] };
    Object.keys(FFP_PROFESSIONAL_ROLES).forEach(cat => {
      groupedOptions[cat] = FFP_PROFESSIONAL_ROLES[cat];
    });
    
    openPicker({
      title: 'Professional Role',
      subtitle: currentRoles.length > 0
        ? 'Pick another role to add, or "Non-professional" to clear all'
        : 'Pick your role — admin will verify credentials separately',
      searchPlaceholder: 'Search roles...',
      options: groupedOptions,
      grouped: true,
      current: null,
      onPick: (val) => {
        if (val === 'Non-professional') {
          // Clear all roles
          this.data.professional = null;
          // PRODUCTION: PATCH /api/members/me { professional: null }
        } else {
          // Add this role if not already present
          if (currentRoleNames.includes(val)) {
            alert(`${val} is already in your professional profile.`);
            return;
          }
          if (!this.data.professional) this.data.professional = { roles: [] };
          this.data.professional.roles.push({ role: val, verified: false });
          // PRODUCTION: POST /api/members/me/professional-roles { role: val }
        }
        this.render();
      }
    });
  },
  
  // Remove a single role by its index in professional.roles
  removeRole(index) {
    if (!this.data.professional || !this.data.professional.roles) return;
    this.data.professional.roles.splice(index, 1);
    if (this.data.professional.roles.length === 0) {
      this.data.professional = null;
    }
    // PRODUCTION: DELETE /api/members/me/professional-roles/{id}
    this.render();
  },
  
  // ===== DOB (native date picker) =====
  setDOBFromNative(iso) {
    if (!iso) return;
    const m = iso.match(/^(\d{4})-(\d{2})-(\d{2})$/);
    if (!m) return;
    this.data.dobYear  = m[1];
    this.data.dobMonth = m[2];
    this.data.dobDay   = m[3];
    this.render();
  },
  
  // ===== PICKER FIELDS =====
  openFieldPicker(field) {
    const cfg = this.pickerConfigFor(field);
    if (!cfg) return;
    openPicker({
      title: cfg.title,
      subtitle: cfg.subtitle || '',
      searchPlaceholder: cfg.searchPlaceholder || 'Search...',
      options: cfg.options,
      grouped: !!cfg.grouped,
      current: this.data[field],
      onPick: (val) => {
        // Handle country change: if current city isn't valid for new country, clear it
        if (field === 'country' && this.data.country !== val) {
          const cities = CITIES_DB[val] || [];
          if (!cities.includes(this.data.city)) this.data.city = '';
        }
        this.data[field] = val;
        this.render();
      }
    });
  },
  
  pickerConfigFor(field) {
    if (field === 'gender')      return { title: 'Gender',      options: GENDERS,                searchPlaceholder: 'Search...' };
    if (field === 'nationality') return { title: 'Nationality', options: NATIONALITIES,          searchPlaceholder: 'Search nationalities...' };
    if (field === 'country')     return { title: 'Country',     options: Object.keys(CITIES_DB), searchPlaceholder: 'Search countries...' };
    if (field === 'city') {
      // City picker is filtered by the currently-selected country
      const cities = CITIES_DB[this.data.country] || [];
      return cities.length === 0
        ? { title: 'City', subtitle: 'Pick a country first', options: [], searchPlaceholder: 'No cities — pick a country first' }
        : { title: `City — ${this.data.country}`, subtitle: 'Filtered by your country', options: cities, searchPlaceholder: 'Search cities...' };
    }
    return null;
  },
  
  // ===== AVATAR =====
  changeAvatar() { alert('Change avatar — wires up to image upload when built.'); },
  
  // ===== PIN =====
  openPinModal() {
    document.getElementById('pin-modal-title').textContent = this.data.hasPin ? 'Change 6-digit PIN' : 'Set 6-digit PIN';
    document.querySelectorAll('#pin-modal input').forEach(i => i.value = '');
    document.getElementById('pin-error').textContent = '';
    document.getElementById('pin-modal').classList.add('show');
    setTimeout(() => {
      const first = document.querySelector('#pin-row-1 input[data-pin="1"]');
      if (first) first.focus();
    }, 50);
  },
  savePin() {
    const pin1 = Array.from(document.querySelectorAll('#pin-row-1 input')).map(i => i.value).join('');
    const pin2 = Array.from(document.querySelectorAll('#pin-row-2 input')).map(i => i.value).join('');
    const err  = document.getElementById('pin-error');
    if (pin1.length !== 6 || !/^\d{6}$/.test(pin1)) { err.textContent = 'PIN must be 6 digits.'; return; }
    if (pin1 !== pin2)                               { err.textContent = 'PINs do not match.'; return; }
    this.data.hasPin = true;
    closePinModal();
    this.render();
  },
  
  // ===== ADD SPORT — chained pickers =====
  addSportFlow() {
    const grouped = {};
    ACTIVITIES_DB.forEach(a => { if (!grouped[a.c]) grouped[a.c] = []; grouped[a.c].push(a.n); });
    openPicker({
      title: 'Add a Skill',
      subtitle: 'Step 1 of 2 — Pick from the FFP activity taxonomy',
      searchPlaceholder: 'Search skills...',
      options: grouped,
      grouped: true,
      onPick: (sportName) => {
        if (this.data.sports.some(s => s.name.toLowerCase() === sportName.toLowerCase())) {
          alert(`${sportName} is already in your profile.`);
          return;
        }
        setTimeout(() => {
          openPicker({
            title: `Skill Level — ${sportName}`,
            subtitle: 'Step 2 of 2 — FFP fitness level',
            searchPlaceholder: 'Search levels...',
            options: FFP_FITNESS_LEVELS,
            onPick: (level) => {
              this.data.sports.push({ name: sportName, level });
              this.render();
            }
          });
        }, 80);
      }
    });
  },
  
  removeSport(index) {
    const sport = this.data.sports[index];
    if (!sport) return;
    // No confirm — easy to re-add via the picker if removed by mistake.
    this.data.sports.splice(index, 1);
    // PRODUCTION: DELETE /api/members/me/skills/{id}
    this.render();
  },
  
  // ===== PREFERENCES =====
  setPref(key, value) {
    this.data.preferences[key] = value;
    // PRODUCTION: PATCH /api/profile/preferences { [key]: value }
  }
};

// ===== PROFILE MODAL HELPERS =====
function closePinModal() { document.getElementById('pin-modal').classList.remove('show'); }

document.addEventListener('input', e => {
  if (e.target.matches('#pin-modal input[data-pin], #pin-modal input[data-pin-confirm]')) {
    e.target.value = e.target.value.replace(/\D/g, '').slice(0, 1);
    if (e.target.value && e.target.nextElementSibling) e.target.nextElementSibling.focus();
  }
});
document.addEventListener('keydown', e => {
  if (e.key === 'Backspace' && e.target.matches('#pin-modal input[data-pin], #pin-modal input[data-pin-confirm]') && !e.target.value && e.target.previousElementSibling) {
    e.target.previousElementSibling.focus();
  }
});


// =====================================================================
// WORKOUT TIMER v76 — Simpler UX with preset chips + EMOM "every X min".
// Modes:
//   Stopwatch:  counts up (no config)
//   Countdown:  duration → beep at zero. Preset chips + min/sec steppers.
//   Interval:   WORK / REST × rounds. Preset chips + steppers.
//   EMOM:       Beep every X minutes (1-10) for N rounds. Reps per round shown.
// Display uses Montserrat throughout (no monospace).
// Beep via WebAudio. State survives panel switches.
// =====================================================================
const WorkoutTimer = {
  s: {
    mode: 'stopwatch',
    running: false,
    elapsedMs: 0,
    startTime: 0,
    rafId: null,
    phase: 'ready',     // 'ready' | 'work' | 'rest' | 'go' | 'done'
    round: 1,
    totalRounds: 1,
    phaseStartMs: 0,
    phaseDurMs: 0,
    // configs
    cdMin: 5, cdSec: 0,
    intWork: 45, intRest: 15, intRounds: 8,
    emInterval: 1, emRounds: 10, emReps: 10   // EMOM: beep every emInterval min × emRounds
  },
  
  audio: null,
  
  init() {
    // Mode tabs (underline style)
    document.querySelectorAll('#timer-tabs .tabs-underline-btn').forEach(btn => {
      btn.addEventListener('click', () => this.setMode(btn.dataset.timerMode));
    });
    // Controls
    document.getElementById('timer-toggle').addEventListener('click', () => this.toggle());
    document.getElementById('timer-reset').addEventListener('click', () => this.reset());
    document.getElementById('timer-skip').addEventListener('click', () => this.skip());
    
    // Preset chips — COUNTDOWN
    document.querySelectorAll('#cd-presets .timer-preset-btn').forEach(btn => {
      btn.addEventListener('click', () => {
        if (this.s.running) return;
        const [m, sec] = btn.dataset.cd.split(',').map(Number);
        this.s.cdMin = m;
        this.s.cdSec = sec;
        this._setActivePreset('#cd-presets', btn);
        this.renderAdjusters();
        this.renderTime();
      });
    });
    // Preset chips — INTERVAL
    document.querySelectorAll('#int-presets .timer-preset-btn').forEach(btn => {
      btn.addEventListener('click', () => {
        if (this.s.running) return;
        const [w, r, rd] = btn.dataset.int.split(',').map(Number);
        this.s.intWork   = w;
        this.s.intRest   = r;
        this.s.intRounds = rd;
        this._setActivePreset('#int-presets', btn);
        this.renderAdjusters();
        this.renderTime();
        this.renderPips();
      });
    });
    // Preset chips — EMOM interval
    document.querySelectorAll('#em-interval-presets .timer-preset-btn').forEach(btn => {
      btn.addEventListener('click', () => {
        if (this.s.running) return;
        this.s.emInterval = parseInt(btn.dataset.emInt, 10);
        this._setActivePreset('#em-interval-presets', btn);
        this.renderTime();
      });
    });
    
    this.applyMode();
    this.renderAdjusters();
    this.renderTime();
    this.renderPips();
  },
  
  _setActivePreset(scope, activeBtn) {
    document.querySelectorAll(scope + ' .timer-preset-btn').forEach(b => b.classList.remove('active'));
    activeBtn.classList.add('active');
  },
  
  // Stepper +/- handler. Deactivates the matching preset row so the user knows they're now in custom mode.
  adj(key, delta) {
    if (this.s.running) return;
    const limits = {
      cdMin:      { min: 0,  max: 90 },
      cdSec:      { min: 0,  max: 55 },
      intWork:    { min: 5,  max: 600 },
      intRest:    { min: 0,  max: 600 },
      intRounds:  { min: 1,  max: 50 },
      emInterval: { min: 1,  max: 10 },
      emRounds:   { min: 1,  max: 50 },
      emReps:     { min: 1,  max: 50 }
    };
    const lim = limits[key];
    if (!lim) return;
    let next = this.s[key] + delta;
    // cdSec wrap: +5 past 55 → minute+1 sec=0; -5 from 0 → minute-1 sec=55
    if (key === 'cdSec' && delta > 0 && this.s.cdSec + delta > 55) {
      this.s.cdMin = Math.min(limits.cdMin.max, this.s.cdMin + 1);
      next = 0;
    } else if (key === 'cdSec' && delta < 0 && this.s.cdSec === 0 && this.s.cdMin > 0) {
      this.s.cdMin = Math.max(0, this.s.cdMin - 1);
      next = 55;
    }
    if (next < lim.min) next = lim.min;
    if (next > lim.max) next = lim.max;
    this.s[key] = next;
    // Custom adjustment → drop active preset state on related row
    if (key === 'cdMin' || key === 'cdSec') {
      document.querySelectorAll('#cd-presets .timer-preset-btn').forEach(b => b.classList.remove('active'));
    } else if (key === 'intWork' || key === 'intRest' || key === 'intRounds') {
      document.querySelectorAll('#int-presets .timer-preset-btn').forEach(b => b.classList.remove('active'));
    }
    this.renderAdjusters();
    this.renderTime();
    if (key === 'intRounds' || key === 'emRounds') this.renderPips();
  },
  
  renderAdjusters() {
    ['cdMin','cdSec','intWork','intRest','intRounds','emInterval','emRounds','emReps'].forEach(k => {
      const el = document.getElementById('adj-' + k);
      if (el) el.value = this.s[k];
    });
  },
  
  setMode(mode) {
    if (this.s.mode === mode) return;
    this.s.mode = mode;
    document.querySelectorAll('#timer-tabs .tabs-underline-btn').forEach(t => {
      t.classList.toggle('active', t.dataset.timerMode === mode);
    });
    this.reset();
    this.applyMode();
  },
  
  applyMode() {
    document.getElementById('config-stopwatch').style.display = this.s.mode === 'stopwatch' ? '' : 'none';
    document.getElementById('config-countdown').style.display = this.s.mode === 'countdown' ? '' : 'none';
    document.getElementById('config-interval').style.display  = this.s.mode === 'interval'  ? '' : 'none';
    document.getElementById('config-emom').style.display      = this.s.mode === 'emom'      ? '' : 'none';
    document.getElementById('timer-skip').style.display = (this.s.mode === 'interval' || this.s.mode === 'emom') ? '' : 'none';
    document.getElementById('timer-pips').style.display = (this.s.mode === 'interval' || this.s.mode === 'emom') ? 'flex' : 'none';
    document.getElementById('timer-time').classList.toggle('stopwatch-mode', this.s.mode === 'stopwatch');
    this.renderTime();
    this.renderPips();
  },
  
  ensureAudio() {
    if (!this.audio) {
      this.audio = new (window.AudioContext || window.webkitAudioContext)();
    }
    if (this.audio.state === 'suspended') this.audio.resume();
  },
  
  beep(freq) {
    try {
      this.ensureAudio();
      const o = this.audio.createOscillator();
      const g = this.audio.createGain();
      o.type = 'sine';
      o.frequency.value = freq || 880;
      g.gain.setValueAtTime(0.001, this.audio.currentTime);
      g.gain.exponentialRampToValueAtTime(0.30, this.audio.currentTime + 0.01);
      g.gain.exponentialRampToValueAtTime(0.001, this.audio.currentTime + 0.15);
      o.connect(g).connect(this.audio.destination);
      o.start(); o.stop(this.audio.currentTime + 0.16);
    } catch (_) {}
  },
  
  toggle() {
    if (this.s.running) this.pause();
    else this.start();
  },
  
  start() {
    if (this.s.running) return;
    this.ensureAudio();
    this.s.running = true;
    this.s.startTime = performance.now() - this.s.elapsedMs;
    document.getElementById('timer-toggle').innerHTML = '<span class="material-icons">pause</span>';
    if (this.s.phase === 'ready') this.beginPhase();
    this.tick();
  },
  
  pause() {
    this.s.running = false;
    cancelAnimationFrame(this.s.rafId);
    document.getElementById('timer-toggle').innerHTML = '<span class="material-icons">play_arrow</span>';
  },
  
  reset() {
    this.pause();
    this.s.elapsedMs = 0;
    this.s.phase = 'ready';
    this.s.round = 1;
    if (this.s.mode === 'interval')   this.s.totalRounds = this.s.intRounds;
    else if (this.s.mode === 'emom')  this.s.totalRounds = this.s.emRounds;
    else this.s.totalRounds = 1;
    this.s.phaseStartMs = 0;
    this.s.phaseDurMs = 0;
    this.setPhaseLabel('READY','phase-ready');
    document.getElementById('timer-meta').textContent = 'Tap start to begin';
    this.renderTime();
    this.renderPips();
  },
  
  skip() {
    if (this.s.mode !== 'interval' && this.s.mode !== 'emom') return;
    this.advancePhase();
  },
  
  beginPhase() {
    if (this.s.mode === 'stopwatch') {
      this.setPhaseLabel('GO','phase-work');
      document.getElementById('timer-meta').textContent = 'Counting up';
    } else if (this.s.mode === 'countdown') {
      this.s.phase = 'go';
      this.s.phaseDurMs = (this.s.cdMin * 60 + this.s.cdSec) * 1000;
      this.s.phaseStartMs = this.s.elapsedMs;
      this.setPhaseLabel('GO','phase-work');
      document.getElementById('timer-meta').textContent = `${this.s.cdMin}m ${this.s.cdSec}s countdown`;
      this.beep(880);
    } else if (this.s.mode === 'interval') {
      this.s.totalRounds = this.s.intRounds;
      this.s.phase = 'work';
      this.s.phaseDurMs = this.s.intWork * 1000;
      this.s.phaseStartMs = this.s.elapsedMs;
      this.setPhaseLabel('WORK','phase-work');
      document.getElementById('timer-meta').textContent = `Round ${this.s.round} of ${this.s.totalRounds}`;
      this.beep(880);
    } else if (this.s.mode === 'emom') {
      this.s.totalRounds = this.s.emRounds;
      this.s.phase = 'go';
      this.s.phaseDurMs = this.s.emInterval * 60 * 1000;
      this.s.phaseStartMs = this.s.elapsedMs;
      this.setPhaseLabel('GO','phase-work');
      const intLabel = this.s.emInterval === 1 ? 'every minute' : `every ${this.s.emInterval} min`;
      document.getElementById('timer-meta').textContent = `Round ${this.s.round} of ${this.s.totalRounds} · ${this.s.emReps} reps · ${intLabel}`;
      this.beep(880);
    }
    this.renderPips();
  },
  
  advancePhase() {
    if (this.s.mode === 'interval') {
      if (this.s.phase === 'work') {
        if (this.s.intRest > 0) {
          this.s.phase = 'rest';
          this.s.phaseDurMs = this.s.intRest * 1000;
          this.s.phaseStartMs = this.s.elapsedMs;
          this.setPhaseLabel('REST','phase-rest');
          this.beep(440);
        } else {
          this.nextRound();
        }
      } else if (this.s.phase === 'rest') {
        this.nextRound();
      }
    } else if (this.s.mode === 'emom') {
      this.nextRound();
    } else if (this.s.mode === 'countdown') {
      this.s.phase = 'done';
      this.setPhaseLabel('DONE','phase-done');
      document.getElementById('timer-meta').textContent = 'Time up';
      this.beep(220); setTimeout(() => this.beep(220), 200); setTimeout(() => this.beep(220), 400);
      this.pause();
    }
  },
  
  nextRound() {
    if (this.s.round >= this.s.totalRounds) {
      this.s.phase = 'done';
      this.setPhaseLabel('DONE','phase-done');
      document.getElementById('timer-meta').textContent = `Workout complete — ${this.s.totalRounds} rounds`;
      this.beep(220); setTimeout(() => this.beep(220), 200); setTimeout(() => this.beep(220), 400);
      this.pause();
      this.renderPips();
      return;
    }
    this.s.round++;
    if (this.s.mode === 'interval') {
      this.s.phase = 'work';
      this.s.phaseDurMs = this.s.intWork * 1000;
      this.s.phaseStartMs = this.s.elapsedMs;
      this.setPhaseLabel('WORK','phase-work');
      document.getElementById('timer-meta').textContent = `Round ${this.s.round} of ${this.s.totalRounds}`;
      this.beep(880);
    } else if (this.s.mode === 'emom') {
      this.s.phaseDurMs = this.s.emInterval * 60 * 1000;
      this.s.phaseStartMs = this.s.elapsedMs;
      this.setPhaseLabel('GO','phase-work');
      const intLabel = this.s.emInterval === 1 ? 'every minute' : `every ${this.s.emInterval} min`;
      document.getElementById('timer-meta').textContent = `Round ${this.s.round} of ${this.s.totalRounds} · ${this.s.emReps} reps · ${intLabel}`;
      this.beep(880);
    }
    this.renderPips();
  },
  
  setPhaseLabel(text, cls) {
    const el = document.getElementById('timer-phase');
    el.textContent = text;
    el.className = 'timer-phase ' + cls;
    this.s.phase = (cls === 'phase-work') ? (this.s.mode === 'interval' ? 'work' : 'go')
                  : (cls === 'phase-rest') ? 'rest'
                  : (cls === 'phase-done') ? 'done' : 'ready';
  },
  
  tick() {
    if (!this.s.running) return;
    this.s.elapsedMs = performance.now() - this.s.startTime;
    if (this.s.mode !== 'stopwatch' && this.s.phase !== 'ready' && this.s.phase !== 'done') {
      const phaseElapsed = this.s.elapsedMs - this.s.phaseStartMs;
      if (phaseElapsed >= this.s.phaseDurMs) {
        this.advancePhase();
      }
    }
    this.renderTime();
    this.s.rafId = requestAnimationFrame(() => this.tick());
  },
  
  renderTime() {
    let ms;
    if (this.s.mode === 'stopwatch') {
      ms = this.s.elapsedMs;
    } else if (this.s.phase === 'ready') {
      if (this.s.mode === 'countdown')      ms = (this.s.cdMin * 60 + this.s.cdSec) * 1000;
      else if (this.s.mode === 'interval')  ms = this.s.intWork * 1000;
      else if (this.s.mode === 'emom')      ms = this.s.emInterval * 60 * 1000;
    } else if (this.s.phase === 'done') {
      ms = 0;
    } else {
      const phaseElapsed = this.s.elapsedMs - this.s.phaseStartMs;
      ms = Math.max(0, this.s.phaseDurMs - phaseElapsed);
    }
    const totalSec = Math.floor(ms / 1000);
    const m = Math.floor(totalSec / 60);
    const sec = totalSec % 60;
    const cs = Math.floor((ms % 1000) / 10);
    document.getElementById('timer-time').textContent = 
      this.s.mode === 'stopwatch'
        ? `${m.toString().padStart(2,'0')}:${sec.toString().padStart(2,'0')}.${cs.toString().padStart(2,'0')}`
        : `${m.toString().padStart(2,'0')}:${sec.toString().padStart(2,'0')}`;
  },
  
  renderPips() {
    const pipsEl = document.getElementById('timer-pips');
    if (this.s.mode !== 'interval' && this.s.mode !== 'emom') {
      pipsEl.innerHTML = '';
      return;
    }
    const total = this.s.mode === 'interval' ? this.s.intRounds : this.s.emRounds;
    let html = '';
    for (let i = 1; i <= total; i++) {
      const cls = (i < this.s.round) ? 'done' : (i === this.s.round && this.s.phase !== 'ready') ? 'active' : '';
      html += `<div class="timer-pip ${cls}"></div>`;
    }
    pipsEl.innerHTML = html;
  }
};

