// ===== VIEW ALL =====
function setupViewAll() {
  document.getElementById('activities-view-all').addEventListener('click', () => { state.expandedActivities = !state.expandedActivities; renderActivities(getFilteredLogs()); });
  document.getElementById('venues-view-all').addEventListener('click', () => { state.expandedVenues = !state.expandedVenues; renderVenues(getFilteredLogs()); });
  document.getElementById('recent-view-all').addEventListener('click', () => { state.expandedRecent = !state.expandedRecent; renderRecent(getFilteredLogs()); });
}

// ===== MAP CONTROLS =====
function setupMap() {
  const svg = document.getElementById('world-svg');
  
  // Pan state
  state.mapPanX = 0;
  state.mapPanY = 0;
  
  function update() {
    const w = 800 / state.mapZoom, h = 400 / state.mapZoom;
    const baseX = (800 - w) / 2, baseY = (400 - h) / 2;
    const x = baseX + state.mapPanX, y = baseY + state.mapPanY;
    svg.setAttribute('viewBox', `${x} ${y} ${w} ${h}`);
  }
  
  document.getElementById('zoom-in').addEventListener('click', () => { 
    if (state.mapZoom < 8) { state.mapZoom *= 1.3; update(); } 
  });
  document.getElementById('zoom-out').addEventListener('click', () => { 
    if (state.mapZoom > 0.8) { state.mapZoom /= 1.3; update(); } 
  });
  document.getElementById('zoom-reset').addEventListener('click', () => { 
    state.mapZoom = 1.5; state.mapPanX = 0; state.mapPanY = 0; update(); 
  });
  
  // Pan controls
  const panStep = () => 40 / state.mapZoom;
  document.getElementById('pan-up').addEventListener('click', () => { state.mapPanY -= panStep(); update(); });
  document.getElementById('pan-down').addEventListener('click', () => { state.mapPanY += panStep(); update(); });
  document.getElementById('pan-left').addEventListener('click', () => { state.mapPanX -= panStep(); update(); });
  document.getElementById('pan-right').addEventListener('click', () => { state.mapPanX += panStep(); update(); });
  
  // Mouse drag to pan
  let isDragging = false;
  let dragStartX = 0, dragStartY = 0;
  let panStartX = 0, panStartY = 0;
  
  svg.addEventListener('mousedown', e => {
    isDragging = true;
    dragStartX = e.clientX;
    dragStartY = e.clientY;
    panStartX = state.mapPanX;
    panStartY = state.mapPanY;
    svg.style.cursor = 'grabbing';
  });
  
  document.addEventListener('mousemove', e => {
    if (!isDragging) return;
    const dx = e.clientX - dragStartX;
    const dy = e.clientY - dragStartY;
    const svgRect = svg.getBoundingClientRect();
    const scaleX = (800 / state.mapZoom) / svgRect.width;
    const scaleY = (400 / state.mapZoom) / svgRect.height;
    state.mapPanX = panStartX - dx * scaleX;
    state.mapPanY = panStartY - dy * scaleY;
    update();
  });
  
  document.addEventListener('mouseup', () => {
    isDragging = false;
    svg.style.cursor = 'grab';
  });
  
  svg.style.cursor = 'grab';
  
  // Touch support for mobile
  svg.addEventListener('touchstart', e => {
    if (e.touches.length !== 1) return;
    isDragging = true;
    dragStartX = e.touches[0].clientX;
    dragStartY = e.touches[0].clientY;
    panStartX = state.mapPanX;
    panStartY = state.mapPanY;
  });
  
  svg.addEventListener('touchmove', e => {
    if (!isDragging || e.touches.length !== 1) return;
    const dx = e.touches[0].clientX - dragStartX;
    const dy = e.touches[0].clientY - dragStartY;
    const svgRect = svg.getBoundingClientRect();
    const scaleX = (800 / state.mapZoom) / svgRect.width;
    const scaleY = (400 / state.mapZoom) / svgRect.height;
    state.mapPanX = panStartX - dx * scaleX;
    state.mapPanY = panStartY - dy * scaleY;
    update();
  });
  
  svg.addEventListener('touchend', () => { isDragging = false; });
}

// ===== ADD CITY MODAL =====
function openAddCity() {
  document.getElementById('add-city-modal').classList.add('show');
  renderCityList('');
  document.getElementById('city-search').focus();
  document.getElementById('city-modal-subtitle').textContent = `${Object.keys(CITIES_DB).length} countries · ${Object.values(CITIES_DB).reduce((s,c)=>s+c.length,0)} cities`;
}
function closeAddCity() { document.getElementById('add-city-modal').classList.remove('show'); }
function renderCityList(filter) {
  const f = (filter||'').toLowerCase().trim();
  const container = document.getElementById('city-list-container');
  let html = '';
  Object.keys(CITIES_DB).forEach(country => {
    const cities = CITIES_DB[country];
    let matches = cities, expand = false;
    if (f) {
      if (country.toLowerCase().includes(f)) { matches = cities; expand = true; }
      else { matches = cities.filter(c => c.toLowerCase().includes(f)); expand = matches.length > 0; }
    }
    if (matches.length === 0) return;
    const id = 'country-' + country.replace(/[^a-zA-Z0-9]/g, '');
    html += `<div class="country-row ${expand?'open':''}" id="${id}">
      <button class="country-toggle" onclick="document.getElementById('${id}').classList.toggle('open')">
        <div class="country-info"><span class="material-icons" style="font-size:16px;color:var(--blue);">public</span><span>${country}</span><span class="count">(${matches.length})</span></div>
        <span class="material-icons chevron">expand_more</span>
      </button>
      <div class="country-cities"><div class="country-cities-inner">
        ${matches.map(city => `<button class="city-pick" data-pick-city="${city.replace(/"/g,'&quot;')}" data-pick-country="${country.replace(/"/g,'&quot;')}"><span class="material-icons">location_on</span><span>${city}</span></button>`).join('')}
      </div></div>
    </div>`;
  });
  if (!html) html = '<div class="empty-state">No cities found</div>';
  container.innerHTML = html;
  
  // Wire up city picker buttons (delegated event handling)
  container.querySelectorAll('.city-pick').forEach(btn => {
    btn.addEventListener('click', () => {
      const city = btn.getAttribute('data-pick-city');
      const country = btn.getAttribute('data-pick-country');
      addCityToWishlist(city, country);
    });
  });
}
function addCityToWishlist(city, country) {
  if (WISHLIST.find(w => w.name === city)) {
    closeAddCity();
    return;
  }
  const visited = LOGS.some(l => l.city === city);
  if (visited) {
    closeAddCity();
    return;
  }
  
  // Add to wishlist
  console.log('[FFP] Adding city to wishlist:', city, country);
  WISHLIST.push({ name: city, country: country, favorite: false });
  closeAddCity();
  
  // Add coordinates if we have them, or estimate from country
  if (!CITY_COORDS[city]) {
    // Estimate coordinates based on country (rough center)
    CITY_COORDS[city] = estimateCityCoords(city, country);
  }
  
  // Switch to "All" filter so the new city is immediately visible
  state.cityFilter = 'all';
  document.querySelectorAll('.city-filter').forEach(b => b.classList.remove('active'));
  const allBtn = document.querySelector('.city-filter[data-filter="all"]');
  if (allBtn) allBtn.classList.add('active');
  
  // Auto-select and zoom to the new city
  state.selectedCity = city;
  const c = CITY_COORDS[city];
  if (c && mapProjection) {
    const [px, py] = mapProjection([c.lng, c.lat]);
    state.mapZoom = 3;
    state.mapPanX = (px - 400);
    state.mapPanY = (py - 200);
  }
  
  renderAll();
  
  // Update map view
  const svg = document.getElementById('world-svg');
  if (svg) {
    const w = 800 / state.mapZoom, h = 400 / state.mapZoom;
    const baseX = (800 - w) / 2, baseY = (400 - h) / 2;
    svg.setAttribute('viewBox', `${baseX + state.mapPanX} ${baseY + state.mapPanY} ${w} ${h}`);
  }
}

// Fallback estimation - only used if city has no coords in CITY_COORDS
function estimateCityCoords(city, country) {
  const COUNTRY_COORDS = {
    'Argentina': [-64, -38], 'Australia': [134, -25], 'Austria': [14, 47], 'Bahrain': [50.55, 26.07],
    'Belgium': [4.5, 50.5], 'Brazil': [-51, -10], 'Canada': [-96, 56], 'Chile': [-71, -36],
    'China': [104, 35], 'Costa Rica': [-83.7, 9.7], 'Czech Republic': [15.5, 49.8],
    'Denmark': [10, 56], 'Egypt': [30, 26], 'Finland': [26, 64], 'France': [2.5, 46.5],
    'Germany': [10.5, 51.5], 'Greece': [22, 39], 'Hungary': [19, 47], 'Iceland': [-19, 65],
    'India': [78, 21], 'Indonesia': [113, -2], 'Ireland': [-8, 53.4], 'Israel': [34.85, 31.5],
    'Italy': [12.5, 43], 'Japan': [138, 36], 'Jordan': [36.5, 30.6], 'Kenya': [37.9, -0.02],
    'Kuwait': [47.5, 29.3], 'Lebanon': [35.8, 33.9], 'Malaysia': [101.9, 4.2], 'Maldives': [73.2, 3.2],
    'Mexico': [-102, 23.6], 'Morocco': [-7.1, 31.8], 'Netherlands': [5.3, 52.1],
    'New Zealand': [171.7, -40.9], 'Norway': [8.5, 60.5], 'Oman': [55.9, 21.5],
    'Philippines': [121.7, 12.9], 'Poland': [19.1, 51.9], 'Portugal': [-8, 39.4],
    'Qatar': [51.2, 25.3], 'Russia': [105, 61.5], 'Saudi Arabia': [45, 23.9],
    'Singapore': [103.8, 1.35], 'South Africa': [22.9, -30.6], 'South Korea': [127.8, 35.9],
    'Spain': [-3.7, 40.5], 'Sri Lanka': [80.8, 7.9], 'Sweden': [18, 60.1],
    'Switzerland': [8.2, 46.8], 'Taiwan': [121, 23.7], 'Tanzania': [34.9, -6.4],
    'Thailand': [101, 15.9], 'Turkey': [35.2, 39], 'United Arab Emirates': [54, 24],
    'United Kingdom': [-3.4, 55.4], 'United States': [-95.7, 37.1], 'Vietnam': [108.3, 14.1]
  };
  const c = COUNTRY_COORDS[country] || [0, 0];
  // Add tiny random offset so cities in same country don't overlap exactly
  const hash = city.split('').reduce((a, c) => ((a << 5) - a) + c.charCodeAt(0) | 0, 0);
  return { lng: c[0] + (hash % 100) / 50 - 1, lat: c[1] + ((hash >> 7) % 100) / 50 - 1, country: country };
}

function removeCity(cityName) {
  const idx = WISHLIST.findIndex(w => w.name === cityName);
  if (idx === -1) return;
  if (confirm(`Remove ${cityName} from your wishlist?`)) {
    WISHLIST.splice(idx, 1);
    if (state.selectedCity === cityName) {
      state.selectedCity = null;
      state.mapZoom = 1;
      state.mapPanX = 0;
      state.mapPanY = 0;
      const svg = document.getElementById('world-svg');
      if (svg) {
        const w = 800 / state.mapZoom, h = 400 / state.mapZoom;
        const baseX = (800 - w) / 2, baseY = (400 - h) / 2;
        svg.setAttribute('viewBox', `${baseX} ${baseY} ${w} ${h}`);
      }
    }
    renderAll();
  }
}

function toggleFavorite(cityName) {
  // Toggle favorite for either wishlist or visited cities
  const wl = WISHLIST.find(w => w.name === cityName);
  if (wl) {
    wl.favorite = !wl.favorite;
    renderAll();
    return;
  }
  const idx = FAVORITES.indexOf(cityName);
  if (idx >= 0) FAVORITES.splice(idx, 1);
  else FAVORITES.push(cityName);
  renderAll();
}

// ===== LOG MODAL =====
function openLogModal() {
  document.getElementById('log-modal').classList.add('show');
  document.getElementById('log-date').value = new Date().toISOString().substring(0,10);
  document.getElementById('log-location').value = 'Dubai';
}
function closeLogModal() { document.getElementById('log-modal').classList.remove('show'); }
function saveLog() {
  const act = document.getElementById('log-activity').value;
  if (!act) { alert('Please select an activity'); return; }
  alert(`Saved: ${act}`);
  closeLogModal();
}

function setupLogPickers() {
  // Activity picker
  const aInput = document.getElementById('log-activity');
  const aPicker = document.getElementById('activity-picker');
  function renderActPicker(filter) {
    const f = (filter||'').toLowerCase().trim();
    let acts = ACTIVITIES_DB;
    if (f) acts = acts.filter(a => a.n.toLowerCase().includes(f) || a.c.toLowerCase().includes(f));
    if (acts.length === 0) { aPicker.innerHTML = '<div class="picker-item" style="color:var(--muted);">No activities</div>'; return; }
    const byCat = {};
    acts.forEach(a => { if (!byCat[a.c]) byCat[a.c] = []; byCat[a.c].push(a); });
    let html = '';
    Object.keys(byCat).forEach(cat => {
      html += `<div class="picker-group-label">${cat}</div>`;
      byCat[cat].forEach(a => {
        html += `<div class="picker-item" onclick="document.getElementById('log-activity').value='${a.n.replace(/'/g, "\'")}'; document.getElementById('activity-picker').classList.remove('show');">${a.n}</div>`;
      });
    });
    aPicker.innerHTML = html;
  }
  aInput.addEventListener('focus', () => { renderActPicker(aInput.value); aPicker.classList.add('show'); });
  aInput.addEventListener('input', () => { renderActPicker(aInput.value); aPicker.classList.add('show'); });
  
  // Location picker
  const lInput = document.getElementById('log-location');
  const lPicker = document.getElementById('location-picker');
  function renderLocPicker(filter) {
    const f = (filter||'').toLowerCase().trim();
    let html = '', count = 0;
    Object.keys(CITIES_DB).forEach(country => {
      const cities = CITIES_DB[country];
      let matches = cities;
      if (f) {
        if (country.toLowerCase().includes(f)) matches = cities;
        else matches = cities.filter(c => c.toLowerCase().includes(f));
      }
      if (matches.length === 0) return;
      html += `<div class="picker-group-label">${country}</div>`;
      matches.forEach(city => {
        count++;
        html += `<div class="picker-item" onclick="document.getElementById('log-location').value='${city.replace(/'/g, "\'")}'; document.getElementById('location-picker').classList.remove('show');"><span class="material-icons" style="font-size:14px;color:var(--blue);">location_on</span>${city}</div>`;
      });
    });
    if (count === 0) html = '<div class="picker-item" style="color:var(--muted);">No locations</div>';
    lPicker.innerHTML = html;
  }
  lInput.addEventListener('focus', () => { renderLocPicker(lInput.value); lPicker.classList.add('show'); });
  lInput.addEventListener('input', () => { renderLocPicker(lInput.value); lPicker.classList.add('show'); });
  
  document.addEventListener('click', e => {
    if (!e.target.closest('.input-wrap')) {
      aPicker.classList.remove('show');
      lPicker.classList.remove('show');
    }
  });
}

// ===== INIT =====
function init() {
  MemberProfile.syncToPassport();  // profile is source of truth — sync before card render
  applyPassportData();
  renderQR();
  setupTopbar();
  setupPanelNav();
  MemberProfile.render();
  WorkoutTimer.init();
  CalorieTracker.init();
  FitnessStats.init();
  Earnings.init();
  Deals.init();
  Events.init();
  Experiences.init();
  MeetMove.init();
  Challenges.init();
  setupTimeFilters();
  setupCityFilters();
  setupViewAll();
  setupMap();
  setupMapProjection();
  loadWorldMap();
  // Apply default zoom (state.mapZoom = 1.5)
  setTimeout(() => {
    const svg = document.getElementById('world-svg');
    if (svg && state.mapZoom !== 1) {
      const w = 800 / state.mapZoom, h = 400 / state.mapZoom;
      const baseX = (800 - w) / 2, baseY = (400 - h) / 2;
      svg.setAttribute('viewBox', `${baseX + state.mapPanX} ${baseY + state.mapPanY} ${w} ${h}`);
    }
  }, 100);
  setupLogPickers();
  document.getElementById('add-city-btn').addEventListener('click', openAddCity);
  document.getElementById('add-city-modal').addEventListener('click', e => { if (e.target.id === 'add-city-modal') closeAddCity(); });
  document.getElementById('log-modal').addEventListener('click', e => { if (e.target.id === 'log-modal') closeLogModal(); });
  document.getElementById('pin-modal').addEventListener('click', e => { if (e.target.id === 'pin-modal') closePinModal(); });
  // Picker modal click-outside is wired inside the Picker module
  document.getElementById('city-search').addEventListener('input', e => renderCityList(e.target.value));
  renderAll();
  console.log('FFP Dashboard v17 - clean build loaded');
}

