// ===== PASSPORT CARD RESPONSIVE SCALING =====
// Locks aspect ratio (1.586:1 credit card / passport ID-1 standard)
// Scales entire card to fit container width on any device
function scalePassportCard() {
  const container = document.querySelector('.pass-container');
  const shell = document.querySelector('.pass-shell');
  if (!container || !shell) return;
  
  const containerWidth = container.offsetWidth;
  const designWidth = 540;
  const scale = containerWidth / designWidth;
  
  shell.style.transform = `scale(${scale})`;
}

window.addEventListener('resize', scalePassportCard);
window.addEventListener('load', scalePassportCard);

if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init);
else init();

// Initial scale after DOM ready
setTimeout(scalePassportCard, 50);
setTimeout(scalePassportCard, 200);
